import{_ as e,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Recursos Avançados: Gerenciamento de Múltiplas Contas | Antigravity Auth","description":"Domine os recursos avançados do plugin Antigravity Auth. Aprofunde-se nos mecanismos principais de balanceamento de carga entre múltiplas contas, seleção inteligente de contas, tratamento de limites de taxa, recuperação de sessão e transformação de requisições.","frontmatter":{"title":"Recursos Avançados: Gerenciamento de Múltiplas Contas | Antigravity Auth","sidebarTitle":"Gerenciar Múltiplas Contas","subtitle":"Recursos Avançados: Gerenciamento de Múltiplas Contas","description":"Domine os recursos avançados do plugin Antigravity Auth. Aprofunde-se nos mecanismos principais de balanceamento de carga entre múltiplas contas, seleção inteligente de contas, tratamento de limites de taxa, recuperação de sessão e transformação de requisições.","order":3},"headers":[],"relativePath":"pt/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"pt/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),s={name:"pt/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function t(n,a,l,d,c,u){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="recursos-avancados" tabindex="-1">Recursos Avançados <a class="header-anchor" href="#recursos-avancados" aria-label="Permalink to &quot;Recursos Avançados&quot;">​</a></h1><p>Este capítulo ajuda você a dominar os recursos avançados do plugin Antigravity Auth, incluindo balanceamento de carga entre múltiplas contas, seleção inteligente de contas, tratamento de limites de taxa, recuperação de sessão, transformação de requisições e outros mecanismos principais. Seja para otimizar a utilização de cotas ou solucionar problemas complexos, aqui estão as respostas que você precisa.</p><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de começar, certifique-se de</p><ul><li>✅ Ter concluído a <a href="./../../start/quick-install/">Instalação Rápida</a> e adicionado a primeira conta com sucesso</li><li>✅ Ter concluído a <a href="./../../start/first-auth-login/">Primeira Autenticação</a> e entendido o fluxo OAuth</li><li>✅ Ter concluído a <a href="./../../start/first-request/">Primeira Requisição</a> e verificado que o plugin funciona corretamente</li></ul></div><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de Aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de Aprendizado&quot;">​</a></h2><h3 id="_1-configuracao-de-multiplas-contas" tabindex="-1">1. <a href="./multi-account-setup/">Configuração de Múltiplas Contas</a> <a class="header-anchor" href="#_1-configuracao-de-multiplas-contas" aria-label="Permalink to &quot;1. [Configuração de Múltiplas Contas](./multi-account-setup/)&quot;">​</a></h3><p>Configure várias contas Google para realizar pool de cotas e balanceamento de carga.</p><ul><li>Adicione várias contas para aumentar o limite total de cotas</li><li>Entenda o sistema de cotas duplo (Antigravity + Gemini CLI)</li><li>Escolha a quantidade adequada de contas de acordo com o cenário</li></ul><h3 id="_2-estrategias-de-selecao-de-contas" tabindex="-1">2. <a href="./account-selection-strategies/">Estratégias de Seleção de Contas</a> <a class="header-anchor" href="#_2-estrategias-de-selecao-de-contas" aria-label="Permalink to &quot;2. [Estratégias de Seleção de Contas](./account-selection-strategies/)&quot;">​</a></h3><p>Domine as melhores práticas das três estratégias de seleção de contas: sticky, round-robin e hybrid.</p><ul><li>1 conta → estratégia sticky para preservar o cache de prompts</li><li>2-3 contas → estratégia hybrid para distribuição inteligente de requisições</li><li>4+ contas → estratégia round-robin para maximizar o throughput</li></ul><h3 id="_3-tratamento-de-limites-de-taxa" tabindex="-1">3. <a href="./rate-limit-handling/">Tratamento de Limites de Taxa</a> <a class="header-anchor" href="#_3-tratamento-de-limites-de-taxa" aria-label="Permalink to &quot;3. [Tratamento de Limites de Taxa](./rate-limit-handling/)&quot;">​</a></h3><p>Entenda os mecanismos de detecção de limites de taxa, tentativas automáticas e alternância de contas.</p><ul><li>Distinga 5 tipos diferentes de erros 429</li><li>Entenda o algoritmo de backoff exponencial para tentativas automáticas</li><li>Domine a lógica de alternância automática em cenários de múltiplas contas</li></ul><h3 id="_4-recuperacao-de-sessao" tabindex="-1">4. <a href="./session-recovery/">Recuperação de Sessão</a> <a class="header-anchor" href="#_4-recuperacao-de-sessao" aria-label="Permalink to &quot;4. [Recuperação de Sessão](./session-recovery/)&quot;">​</a></h3><p>Conheça o mecanismo de recuperação de sessão para tratamento automático de falhas e interrupções em chamadas de ferramentas.</p><ul><li>Tratamento automático do erro tool_result_missing</li><li>Correção do problema thinking_block_order</li><li>Configuração das opções auto_resume e session_recovery</li></ul><h3 id="_5-mecanismo-de-transformacao-de-requisicoes" tabindex="-1">5. <a href="./request-transformation/">Mecanismo de Transformação de Requisições</a> <a class="header-anchor" href="#_5-mecanismo-de-transformacao-de-requisicoes" aria-label="Permalink to &quot;5. [Mecanismo de Transformação de Requisições](./request-transformation/)&quot;">​</a></h3><p>Aprofunde-se no mecanismo de transformação de requisições e como compatibilizar as diferenças de protocolo entre diferentes modelos de IA.</p><ul><li>Entenda as diferenças de protocolo entre modelos Claude e Gemini</li><li>Solucione erros 400 causados por incompatibilidade de Schema</li><li>Otimize a configuração de Thinking para obter o melhor desempenho</li></ul><h3 id="_6-guia-de-configuracao" tabindex="-1">6. <a href="./configuration-guide/">Guia de Configuração</a> <a class="header-anchor" href="#_6-guia-de-configuracao" aria-label="Permalink to &quot;6. [Guia de Configuração](./configuration-guide/)&quot;">​</a></h3><p>Domine todas as opções de configuração para personalizar o comportamento do plugin conforme necessário.</p><ul><li>Localização e prioridade dos arquivos de configuração</li><li>Configurações de comportamento do modelo, rotação de contas e comportamento da aplicação</li><li>Configurações recomendadas para cenários de conta única, múltiplas contas e agentes paralelos</li></ul><h3 id="_7-otimizacao-para-agentes-paralelos" tabindex="-1">7. <a href="./parallel-agents/">Otimização para Agentes Paralelos</a> <a class="header-anchor" href="#_7-otimizacao-para-agentes-paralelos" aria-label="Permalink to &quot;7. [Otimização para Agentes Paralelos](./parallel-agents/)&quot;">​</a></h3><p>Otimize a alocação de contas para cenários de agentes paralelos, habilitando o deslocamento de PID.</p><ul><li>Entenda os problemas de conflito de contas em cenários de agentes paralelos</li><li>Habilite o deslocamento de PID para que processos diferentes priorizem contas diferentes</li><li>Combine com a estratégia round-robin para maximizar a utilização de múltiplas contas</li></ul><h3 id="_8-logs-de-depuracao" tabindex="-1">8. <a href="./debug-logging/">Logs de Depuração</a> <a class="header-anchor" href="#_8-logs-de-depuracao" aria-label="Permalink to &quot;8. [Logs de Depuração](./debug-logging/)&quot;">​</a></h3><p>Habilite os logs de depuração para solucionar problemas e monitorar o estado de execução.</p><ul><li>Habilite logs de depuração para registrar informações detalhadas</li><li>Entenda os diferentes níveis de log e cenários de aplicação</li><li>Interprete o conteúdo dos logs para localizar problemas rapidamente</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir o aprendizado dos recursos avançados, você pode:</p><ul><li>📖 Consultar as <a href="./../../faq/">Perguntas Frequentes</a> para resolver problemas encontrados durante o uso</li><li>📚 Ler o <a href="./../../appendix/">Apêndice</a> para entender o design da arquitetura e referência completa de configuração</li><li>🔄 Acompanhar o <a href="./../../changelog/">Changelog</a> para obter as últimas funcionalidades e alterações</li></ul>',32)])])}const h=e(s,[["render",t]]);export{p as __pageData,h as default};
